+// ============================================================================
+// Step Types
+// ============================================================================
+
+/**
+ * Configuration for a single operator step
+ */
+export interface OperatorStepConfig {
+  /** Unique step identifier */
+  id: string;
+
+  /** Display name */
+  name: string;
+
+  /** Description shown to user */
